  1	import React, { FC } from 'react';
  2	import { useParams } from 'react-router-dom-v5-compat';
  3	
  4	import {
  5	  ConfigMapModel,
  6	  modelToGroupVersionKind,
  7	  V1Template,
  8	} from '@kubevirt-ui/kubevirt-api/console';
  9	import { IoK8sApiCoreV1ConfigMap } from '@kubevirt-ui/kubevirt-api/kubernetes';
 10	import WindowsLabel from '@kubevirt-utils/components/Labels/WindowsLabel';
 11	import { useModal } from '@kubevirt-utils/components/ModalProvider/ModalProvider';
 12	import { AUTOUNATTEND, UNATTEND } from '@kubevirt-utils/components/SysprepModal/sysprep-utils';
 13	import { SysprepDescription } from '@kubevirt-utils/components/SysprepModal/SysprepDescription';
 14	import { SysprepModal } from '@kubevirt-utils/components/SysprepModal/SysprepModal';
 15	import VirtualMachineDescriptionItem from '@kubevirt-utils/components/VirtualMachineDescriptionItem/VirtualMachineDescriptionItem';
 16	import { DEFAULT_NAMESPACE } from '@kubevirt-utils/constants/constants';
 17	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 18	import { getTemplateVirtualMachineObject } from '@kubevirt-utils/resources/template';
 19	import { getVolumes } from '@kubevirt-utils/resources/vm';
 20	import { isEmpty } from '@kubevirt-utils/utils/utils';
 21	import { useK8sWatchResource } from '@openshift-console/dynamic-plugin-sdk';
 22	import { Button, Flex, FlexItem, Title } from '@patternfly/react-core';
 23	import { PencilAltIcon } from '@patternfly/react-icons';
 24	
 25	import useEditTemplateAccessReview from '../../../../hooks/useIsTemplateEditable';
 26	
 27	import {
 28	  deleteTemplateSysprepObject,
 29	  getTemplateSysprepObject,
 30	  replaceTemplateSysprepObject,
 31	  updateSysprepObject,
 32	  updateTemplateWithSysprep,
 33	} from './sysprep-utils';
 34	
 35	type SysPrepItemProps = {
 36	  template: V1Template;
 37	};
 38	
 39	const SysPrepItem: FC<SysPrepItemProps> = ({ template }) => {
 40	  const { ns: namespace } = useParams<{ ns: string }>();
 41	  const { isTemplateEditable } = useEditTemplateAccessReview(template);
 42	  const vm = getTemplateVirtualMachineObject(template);
 43	  const currentVMSysprepName = getVolumes(vm)?.find((volume) => volume?.sysprep?.configMap?.name)
 44	    ?.sysprep?.configMap?.name;
 45	
 46	  const sysPrepObject = getTemplateSysprepObject(template, currentVMSysprepName);
 47	
 48	  const { t } = useKubevirtTranslation();
 49	  const { createModal } = useModal();
 50	
 51	  const externalSysprepSelected = isEmpty(sysPrepObject) && currentVMSysprepName;
 52	
 53	  const [externalSysprepConfig, sysprepLoaded, sysprepLoadError] =
 54	    useK8sWatchResource<IoK8sApiCoreV1ConfigMap>(
 55	      externalSysprepSelected
 56	        ? {
 57	            groupVersionKind: modelToGroupVersionKind(ConfigMapModel),
 58	            name: externalSysprepSelected,
 59	            namespace,
 60	          }
 61	        : null,
 62	    );
 63	
 64	  const { [AUTOUNATTEND]: autoUnattend, [UNATTEND]: unattend } =
 65	    externalSysprepConfig?.data || sysPrepObject?.data || {};
 66	
 67	  const onSysprepSelected = async (newSysprepName: string) => {
 68	    const templateNoSysprepObj = deleteTemplateSysprepObject(template, currentVMSysprepName);
 69	    return updateTemplateWithSysprep(templateNoSysprepObj, newSysprepName, currentVMSysprepName);
 70	  };
 71	
 72	  const onSysprepCreation = (newUnattended: string, newAutoUnattend: string) => {
 73	    const newSysPrepObject = updateSysprepObject(sysPrepObject, newUnattended, newAutoUnattend);
 74	    const templateWithSysPrep = newSysPrepObject
 75	      ? replaceTemplateSysprepObject(template, newSysPrepObject, currentVMSysprepName)
 76	      : deleteTemplateSysprepObject(template, currentVMSysprepName);
 77	
 78	    return updateTemplateWithSysprep(
 79	      templateWithSysPrep,
 80	      newSysPrepObject?.metadata?.name,
 81	      externalSysprepSelected,
 82	    );
 83	  };
 84	
 85	  return (
 86	    <VirtualMachineDescriptionItem
 87	      descriptionHeader={
 88	        <Flex className="vm-description-item__title">
 89	          <FlexItem>
 90	            <Title headingLevel="h2">
 91	              {t('Sysprep')} {<WindowsLabel />}
 92	            </Title>
 93	          </FlexItem>
 94	          <FlexItem>
 95	            <Button
 96	              onClick={() =>
 97	                createModal((modalProps) => (
 98	                  <SysprepModal
 99	                    {...modalProps}
100	                    autoUnattend={autoUnattend}
101	                    namespace={vm?.metadata?.namespace || DEFAULT_NAMESPACE}
102	                    onSysprepCreation={onSysprepCreation}
103	                    onSysprepSelected={onSysprepSelected}
104	                    sysprepSelected={externalSysprepSelected}
105	                    unattend={unattend}
106	                  />
107	                ))
108	              }
109	              isDisabled={!isTemplateEditable}
110	              isInline
111	              type="button"
112	              variant="link"
113	            >
114	              {t('Edit')}
115	              <PencilAltIcon className="co-icon-space-l pf-v6-c-button-icon--plain" />
116	            </Button>
117	          </FlexItem>
118	        </Flex>
119	      }
120	      descriptionData={<SysprepDescription error={sysprepLoadError} loaded={sysprepLoaded} />}
121	    />
122	  );
123	};
124	
125	export default SysPrepItem;

